sol! {
    event CallExecuted(
        uint256 indexed callId,
        address indexed to,
        address indexed caller,
        uint32 startBlock,
        uint32 numCalls,
        uint32 frequency,
        uint256 executionIndex,
        uint256 gasUsed,
        uint256 feesPaid
    );

    event CallExecutionFailed(
        uint256 indexed callId,
        address indexed to,
        address indexed caller,
        uint32 startBlock,
        uint32 numCalls,
        uint32 frequency,
        uint256 executionIndex,
        uint256 gasUsed,
        string reason
    );

    event CallExpired(...);
    event CallSkippedTTLExpired(...);
    event CallSkippedInsufficientFunds(...);
}

pub enum ScheduledTxGasResult {
    Success { callback_gas: u64, call_id: U256 },
    Failed { callback_gas: u64, call_id: U256 },
    Skipped { call_id: U256, reason: SkipReason },
    EventNotFound,
}

pub fn extract_scheduled_callback_gas(
    logs: &[Log],
    scheduler_address: Address,
) -> ScheduledTxGasResult {
    for log in logs {
        if log.address != scheduler_address {
            continue;
        }

        if log.topics().is_empty() {
            continue;
        }

        if log.topics()[0] == CallExecuted::SIGNATURE_HASH {
            if let Ok(event) = CallExecuted::decode_log(log) {
                match event.gasUsed.try_into() {
                    Ok(gas) => {
                        return ScheduledTxGasResult::Success {
                            callback_gas: gas,
                            call_id: event.callId,
                        }
                    }
                    Err(_) => {
                        continue;
                    }
                }
            }
        }

        if log.topics()[0] == CallExecutionFailed::SIGNATURE_HASH { ... }
    }

    ScheduledTxGasResult::EventNotFound
}

if log.topics()[0] == CallExpired::SIGNATURE_HASH {
    if let Ok(event) = CallExpired::decode_log(log) {
        return ScheduledTxGasResult::Skipped {
            call_id: event.callId,
            reason: SkipReason::Expired,
        };
    }
}

if log.topics()[0] == CallSkippedTTLExpired::SIGNATURE_HASH { ... SkipReason::TTLExpired ... }

if log.topics()[0] == CallSkippedInsufficientFunds::SIGNATURE_HASH { ... SkipReason::InsufficientFunds ... }

pub fn get_callback_gas(result: &ScheduledTxGasResult) -> Option<u64> {
    match result {
        ScheduledTxGasResult::Success { callback_gas, .. } => Some(*callback_gas),
        ScheduledTxGasResult::Failed { callback_gas, .. } => Some(*callback_gas),
        ScheduledTxGasResult::Skipped { .. } => Some(0),
        ScheduledTxGasResult::EventNotFound => None,
    }
}

pub fn get_callback_gas(result: &ScheduledTxGasResult) -> Option<u64> { ... }

#[deprecated(note = "Use get_callback_gas() instead - fallbacks are dangerous in consensus code")]
pub fn get_callback_gas_or_fallback(result: &ScheduledTxGasResult, fallback: u64) -> u64 {
    get_callback_gas(result).unwrap_or(fallback)
}

